use std::collections::HashSet;

#[derive(Debug, Eq, PartialEq, Hash, Clone)]
struct GameEvent {
    type_id: u32,
    timestamp: i64,
}

fn flatten_nested_events(nested_list: Vec<Vec<Vec<GameEvent>>>) -> HashSet<GameEvent> {
    let mut unique_events = HashSet::new();

    for level1_vec in nested_list {
        for level2_vec in level1_vec {
            for event in level2_vec {
                unique_events.insert(event);
            }
        }
    }
    unique_events
}

fn main() {
    let events = vec![ 
        vec![ 
            vec![GameEvent { type_id: 1, timestamp: 100 }],
            vec![GameEvent { type_id: 2, timestamp: 200 }]
        ],
        vec![ 
            vec![GameEvent { type_id: 3, timestamp: 300 }]
        ]
    ];

    let result = flatten_nested_events(events);
    println!("Flattened and unique events found: {:?}", result);
}

use std::collections::HashSet;

fn main() {
    let nested_data: Vec<Vec<i32>> = vec![vec![1, 2], vec![3, 4, 5], vec![6]];

    let mut flattened_set: HashSet<i32> = HashSet::new();
    for inner_vec in nested_data {
        for item in inner_vec {
            flattened_set.insert(item);
        }
    }

    let mut result: Vec<i32> = Vec::new();
    for item in flattened_set.into_iter() {
        result.push(item);
    }

    println!("Flattened and unique elements: {:?}", result);
}

use std::collections::VecDeque;

fn process_sensor_data(nested_readings: Vec<Vec<f64>>) -> Vec<f64> {
    let mut flattened_data = Vec::new();
    for inner_list in nested_readings {
        flattened_data.extend(inner_list);
    }
    flattened_data
}

fn main() {
    let sensor_a_readings = vec![10.5, 11.2, 9.8];
    let sensor_b_readings = vec![20.1, 21.5, 19.9];
    let sensor_c_readings = vec![30.0, 30.5];

    let all_nested_data = vec![sensor_a_readings, sensor_b_readings, sensor_c_readings];

    let combined_readings = process_sensor_data(all_nested_data);

    println!("Total flattened data points: {}", combined_readings.len());
    println!("First 5 readings: {:?}", &combined_readings[0..5]);
}

use std::collections::HashMap;

struct Config {
    name: String,
    value: Option<String>,
    nested_settings: Vec<Config>,
}

fn flatten_configs(mut configs: Vec<Config>) -> HashMap<String, String> {
    let mut flat_map = HashMap::new();
    for config in configs.drain(..) {
        flatten_configs_recursive(&config, &mut flat_map);
    }
    flat_map
}

fn flatten_configs_recursive(config: &Config, result: &mut HashMap<String, String>) {
    let key = format!("{}", config.name);
    if let Some(value) = &config.value {
        result.insert(key, value.clone());
    }

    for nested_config in &config.nested_settings {
        let mut temp_map = HashMap::new();
        flatten_configs_recursive(nested_config, &mut temp_map);
        for (k, v) in temp_map {
            result.insert(format!("{}:{}", config.name, k), v);
        }
    }
}

use std::collections::VecDeque;

#[derive(Debug)]
struct StatusBlock {
    id: u32,
    flags: Vec<u8>,
}

fn flatten_status_blocks(blocks: &Vec<StatusBlock>) -> Vec<u8> {
    let mut flattened = VecDeque::new();
    for block in blocks.iter() {
        for flag in block.flags.iter() {
            flattened.push_back(*flag);
        }
    }
    flattened.into_iter().collect()
}

fn main() {
    let primary_blocks = vec![
        StatusBlock { id: 0xDEADBEEF, flags: vec![0b1010, 0b0101] },
        StatusBlock { id: 0xCAFEBABE, flags: vec![0b1111] },
    ];

    let combined_flags = flatten_status_blocks(&primary_blocks);
    println!("Flattened data stream: {:?}", combined_flags);
}
